src/interfaces/pool/ICLPoolState.sol.content:
// SPDX-License-Identifier: GPL-2.0-or-later
pragma solidity ^0.8.0;

/// @title Pool state that can change
/// @notice These methods compose the pool's state, and can change with any frequency including multiple times
/// per transaction
interface ICLPoolState {
    /// @notice The 0th storage slot in the pool stores many values, and is exposed as a single method to save gas
    /// when accessed externally.
    /// @return sqrtPriceX96 The current price of the pool as a sqrt(token1/token0) Q64.96 value
    /// tick The current tick of the pool, i.e. according to the last tick transition that was run.
    /// This value may not always be equal to SqrtTickMath.getTickAtSqrtRatio(sqrtPriceX96) if the price is on a tick
    /// boundary.
    /// observationIndex The index of the last oracle observation that was written,
    /// observationCardinality The current maximum number of observations stored in the pool,
    /// observationCardinalityNext The next maximum number of observations, to be updated when the observation.
    /// unlocked Whether the pool is currently locked to reentrancy
    function slot0()
        external
        view
        returns (
            uint160 sqrtPriceX96,
            int24 tick,
            uint16 observationIndex,
            uint16 observationCardinality,
            uint16 observationCardinalityNext,
            bool unlocked
        );

    /// @notice The pool's swap & flash fee in pips, i.e. 1e-6
    /// @dev Can be modified in PoolFactory on a pool basis or upgraded to be dynamic.
    /// @return The swap & flash fee
    function fee() external view returns (uint24);

    /// @notice The pool's unstaked fee in pips, i.e. 1e-6
    /// @dev Can be modified in PoolFactory on a pool basis or upgraded to be dynamic.
    /// @return The unstaked fee
    function unstakedFee() external view returns (uint24);

    /// @notice The fee growth as a Q128.128 fees of token0 collected per unit of liquidity for the entire life of the pool
    /// @dev This value can overflow the uint256
    function feeGrowthGlobal0X128() external view returns (uint256);

    /// @notice The fee growth as a Q128.128 fees of token1 collected per unit of liquidity for the entire life of the pool
    /// @dev This value can overflow the uint256
    function feeGrowthGlobal1X128() external view returns (uint256);

    /// @notice The reward growth as a Q128.128 rewards of emission collected per unit of liquidity for the entire life of the pool
    /// @dev This value can overflow the uint256
    function rewardGrowthGlobalX128() external view returns (uint256);

    /// @notice The amounts of token0 and token1 that are owed to the gauge
    /// @dev Gauge fees will never exceed uint128 max in either token
    function gaugeFees() external view returns (uint128 token0, uint128 token1);

    /// @notice the emission rate of time-based farming
    function rewardRate() external view returns (uint256);

    /// @notice acts as a virtual reserve that holds information on how many rewards are yet to be distributed
    function rewardReserve() external view returns (uint256);

    /// @notice timestamp of the end of the current epoch's rewards
    function periodFinish() external view returns (uint256);

    /// @notice last time the rewardReserve and rewardRate were updated
    function lastUpdated() external view returns (uint32);

    /// @notice tracks total rewards distributed when no staked liquidity in active tick for epoch ending at periodFinish
    /// @notice this amount is rolled over on the next call to notifyRewardAmount
    /// @dev rollover will always be smaller than the rewards distributed that epoch
    function rollover() external view returns (uint256);

    /// @notice The currently in range liquidity available to the pool
    /// @dev This value has no relationship to the total liquidity across all ticks
    /// @dev This value includes staked liquidity
    function liquidity() external view returns (uint128);

    /// @notice The currently in range staked liquidity available to the pool
    /// @dev This value has no relationship to the total staked liquidity across all ticks
    function stakedLiquidity() external view returns (uint128);

    /// @notice Look up information about a specific tick in the pool
    /// @param tick The tick to look up
    /// @return liquidityGross the total amount of position liquidity that uses the pool either as tick lower or
    /// tick upper,
    /// liquidityNet how much liquidity changes when the pool price crosses the tick,
    /// stakedLiquidityNet how much staked liquidity changes when the pool price crosses the tick,
    /// feeGrowthOutside0X128 the fee growth on the other side of the tick from the current tick in token0,
    /// feeGrowthOutside1X128 the fee growth on the other side of the tick from the current tick in token1,
    /// rewardGrowthOutsideX128 the reward growth on the other side of the tick from the current tick in emission token
    /// tickCumulativeOutside the cumulative tick value on the other side of the tick from the current tick
    /// secondsPerLiquidityOutsideX128 the seconds spent per liquidity on the other side of the tick from the current tick,
    /// secondsOutside the seconds spent on the other side of the tick from the current tick,
    /// initialized Set to true if the tick is initialized, i.e. liquidityGross is greater than 0, otherwise equal to false.
    /// Outside values can only be used if the tick is initialized, i.e. if liquidityGross is greater than 0.
    /// In addition, these values are only relative and must be used only in comparison to previous snapshots for
    /// a specific position.
    function ticks(
        int24 tick
    )
        external
        view
        returns (
            uint128 liquidityGross,
            int128 liquidityNet,
            int128 stakedLiquidityNet,
            uint256 feeGrowthOutside0X128,
            uint256 feeGrowthOutside1X128,
            uint256 rewardGrowthOutsideX128,
            int56 tickCumulativeOutside,
            uint160 secondsPerLiquidityOutsideX128,
            uint32 secondsOutside,
            bool initialized
        );

    /// @notice Returns 256 packed tick initialized boolean values. See TickBitmap for more information
    function tickBitmap(int16 wordPosition) external view returns (uint256);

    /// @notice Returns the information about a position by the position's key
    /// @param key The position's key is a hash of a preimage composed by the owner, tickLower and tickUpper
    /// @return _liquidity The amount of liquidity in the position,
    /// Returns feeGrowthInside0LastX128 fee growth of token0 inside the tick range as of the last mint/burn/poke,
    /// Returns feeGrowthInside1LastX128 fee growth of token1 inside the tick range as of the last mint/burn/poke,
    /// Returns tokensOwed0 the computed amount of token0 owed to the position as of the last mint/burn/poke,
    /// Returns tokensOwed1 the computed amount of token1 owed to the position as of the last mint/burn/poke
    function positions(
        bytes32 key
    )
        external
        view
        returns (
            uint128 _liquidity,
            uint256 feeGrowthInside0LastX128,
            uint256 feeGrowthInside1LastX128,
            uint128 tokensOwed0,
            uint128 tokensOwed1
        );

    /// @notice Returns data about a specific observation index
    /// @param index The element of the observations array to fetch
    /// @dev You most likely want to use #observe() instead of this method to get an observation as of some amount of time
    /// ago, rather than at a specific index in the array.
    /// @return blockTimestamp The timestamp of the observation,
    /// Returns tickCumulative the tick multiplied by seconds elapsed for the life of the pool as of the observation timestamp,
    /// Returns secondsPerLiquidityCumulativeX128 the seconds per in range liquidity for the life of the pool as of the observation timestamp,
    /// Returns initialized whether the observation has been initialized and the values are safe to use
    function observations(
        uint256 index
    )
        external
        view
        returns (
            uint32 blockTimestamp,
            int56 tickCumulative,
            uint160 secondsPerLiquidityCumulativeX128,
            bool initialized
        );

    /// @notice Returns data about reward growth within a tick range.
    /// RewardGrowthGlobalX128 can be supplied as a parameter for claimable reward calculations.
    /// @dev Used in gauge reward/earned calculations
    /// @param tickLower The lower tick of the range
    /// @param tickUpper The upper tick of the range
    /// @param _rewardGrowthGlobalX128 a calculated rewardGrowthGlobalX128 or 0 (in case of 0 it means we use the rewardGrowthGlobalX128 from state)
    /// @return rewardGrowthInsideX128 The reward growth in the range
    function getRewardGrowthInside(
        int24 tickLower,
        int24 tickUpper,
        uint256 _rewardGrowthGlobalX128
    ) external view returns (uint256 rewardGrowthInsideX128);
}

test/BaseTest.sol.content:
// SPDX-License-Identifier: UNLICENSED
pragma solidity ^0.8.13;

import "forge-std/Test.sol";
import "../src/RebalancerVault.sol";
import "./mocks/MockERC20.sol";
import "./mocks/MockCLPool.sol";
import "./mocks/MockPositionManager.sol";
import "./mocks/MockCLSwapRouter.sol";

abstract contract BaseTest is Test {
    // ── Actors ───────────────────────────────────────────────────────────────
    address internal owner = makeAddr("owner");
    address internal operator = makeAddr("operator");
    address internal alice = makeAddr("alice");
    address internal bob = makeAddr("bob");
    address internal carol = makeAddr("carol");
    address internal feeRecip = makeAddr("feeRecipient");

    // ── Contracts ────────────────────────────────────────────────────────────
    MockERC20 internal token0; // BTC-like,  8 decimals
    MockERC20 internal token1; // MUSD-like, 18 decimals
    MockCLPool internal pool;
    MockPositionManager internal pm;
    MockCLSwapRouter internal router;
    RebalancerVault public vault;

    uint160 internal constant SQRT_PRICE_100K =
        2_505_414_483_750_479_251_915_866_636;
    int24 internal constant TICK_100K = 345_397; // log(1e15)/log(1.0001)
    int24 internal constant TICK_SPACING = 200;

    uint256 public constant DEAD_SHARES = 1_000;
    uint256 internal constant INITIAL_DEPOSIT = 1e8;

    // ── Setup ────────────────────────────────────────────────────────────────
    function setUp() public virtual {
        // Ensure block.timestamp > twapSeconds (300) so observe() subtraction doesn't underflow.
        vm.warp(10_000);

        token0 = new MockERC20("Bitcoin", "BTC", 8);
        token1 = new MockERC20("Mezo USD", "MUSD", 18);

        pool = new MockCLPool();

        pool.initialize(
            address(0),
            address(token0),
            address(token1),
            TICK_SPACING,
            address(0),
            SQRT_PRICE_100K
        );

        pool.setPrice(SQRT_PRICE_100K, TICK_100K);

        pm = new MockPositionManager();
        router = new MockCLSwapRouter();

        vault = new RebalancerVault(
            owner,
            address(pool),
            operator,
            "Rebalancer BTC/MUSD",
            "rbBTC"
        );

        vm.etch(address(vault.positionManager()), address(pm).code);

        vm.etch(address(vault.clSwapRouter()), address(router).code);

        _fundActors();

        _approveAll();
    }

    // ── Internal setup helpers ────────────────────────────────────────────────

    function _fundActors() internal {
        uint256 btc = 100e8;
        uint256 musd = 1e25;

        token0.mint(alice, btc);
        token0.mint(bob, btc);
        token0.mint(carol, btc);
        token0.mint(owner, btc);

        token1.mint(alice, musd);
        token1.mint(bob, musd);
        token1.mint(carol, musd);
        token1.mint(owner, musd);

        token0.mint(address(pm), 100e8);
        token1.mint(address(pm), 1e25);
        token0.mint(address(router), 100e8);
        token1.mint(address(router), 1e25);
    }

    function _approveAll() internal {
        address[4] memory actors = [alice, bob, carol, owner];
        for (uint i = 0; i < actors.length; i++) {
            vm.startPrank(actors[i]);
            token0.approve(address(vault), type(uint256).max);
            token1.approve(address(vault), type(uint256).max);
            vm.stopPrank();
        }
    }

    // ── Test helpers ──────────────────────────────────────────────────────────

    /// @dev Seeds vault with dead shares via alice's first deposit.
    ///      Advances one block so subsequent withdraw/redeem can pass the same-block guard.
    function _initialDeposit(uint256 assets) internal returns (uint256 shares) {
        vm.prank(alice);
        shares = vault.deposit(assets, alice);
        vm.roll(block.number + 1);
    }

    /// @dev Initializes an LP position in the vault (owner only).
    function _initPosition(
        int24 tickLower,
        int24 tickUpper,
        uint256 amt0,
        uint256 amt1
    ) internal {
        vm.startPrank(owner);
        token0.transfer(address(vault), amt0);
        token1.transfer(address(vault), amt1);
        vault.initializePosition(tickLower, tickUpper, amt0, amt1, 0, 0);
        vm.stopPrank();
    }

    /// @dev Returns a tick range aligned to TICK_SPACING around TICK_100K.
    function _defaultRange() internal pure returns (int24 lo, int24 hi) {
        lo = ((TICK_100K - 2000) / TICK_SPACING) * TICK_SPACING;
        hi = ((TICK_100K + 2000) / TICK_SPACING) * TICK_SPACING;
    }

    /// @dev Warps past the 2-day fee timelock.
    function _warpPastTimelock() internal {
        vm.warp(block.timestamp + 3 days);
    }

    /// @dev Proposes and applies a performance fee in one call.
    function _setFee(uint256 bps) internal {
        vm.startPrank(owner);
        vault.proposePerformanceFee(bps, feeRecip);
        _warpPastTimelock();
        vault.applyPerformanceFee();
        vm.stopPrank();
    }

    /// @dev Simulate price movement on the mock pool.
    function _setPoolPrice(uint160 sqrtPriceX96, int24 tick) internal {
        pool.setPrice(sqrtPriceX96, tick);
    }
}

